CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TABLE organizations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), oidc_subject text UNIQUE NOT NULL, email text UNIQUE NOT NULL, name text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE memberships (user_id uuid REFERENCES users(id) ON DELETE CASCADE, organization_id uuid REFERENCES organizations(id) ON DELETE CASCADE, role text NOT NULL CHECK (role IN ('viewer','analyst','steward','admin','auditor')), PRIMARY KEY(user_id, organization_id));
CREATE TABLE datasets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), name text NOT NULL, classification text NOT NULL DEFAULT 'internal', schema_json jsonb NOT NULL DEFAULT '{}', rows_json jsonb NOT NULL DEFAULT '[]', version integer NOT NULL DEFAULT 1, created_by uuid REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE metrics (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), name text NOT NULL, expression jsonb NOT NULL, owner_id uuid REFERENCES users(id), status text NOT NULL DEFAULT 'draft' CHECK(status IN ('draft','approved','retired')), version integer NOT NULL DEFAULT 1, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(organization_id,name,version));
CREATE TABLE analyses (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), dataset_id uuid REFERENCES datasets(id), question text NOT NULL, plan jsonb NOT NULL, result jsonb, status text NOT NULL DEFAULT 'queued', created_by uuid REFERENCES users(id), created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE audit_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), organization_id uuid NOT NULL REFERENCES organizations(id), actor_id uuid REFERENCES users(id), event_type text NOT NULL, entity_type text NOT NULL, entity_id uuid, metadata jsonb NOT NULL DEFAULT '{}', created_at timestamptz NOT NULL DEFAULT now());
ALTER TABLE datasets ENABLE ROW LEVEL SECURITY; ALTER TABLE metrics ENABLE ROW LEVEL SECURITY; ALTER TABLE analyses ENABLE ROW LEVEL SECURITY; ALTER TABLE audit_events ENABLE ROW LEVEL SECURITY;
CREATE POLICY dataset_tenant_isolation ON datasets USING (organization_id = current_setting('app.organization_id', true)::uuid);
CREATE POLICY metric_tenant_isolation ON metrics USING (organization_id = current_setting('app.organization_id', true)::uuid);
CREATE POLICY analysis_tenant_isolation ON analyses USING (organization_id = current_setting('app.organization_id', true)::uuid);
CREATE POLICY audit_tenant_isolation ON audit_events USING (organization_id = current_setting('app.organization_id', true)::uuid);
